export interface LogoGenerationRequest {
  name: string;
  style: string;
  colorScheme: string;
}

export interface LogoProcessorOptions {
  removeBackground: boolean;
  size: 512 | 48 | 24; // 512 is original/preview
  format: 'png' | 'svg';
}

export enum GenerationStatus {
  IDLE = 'IDLE',
  GENERATING = 'GENERATING',
  PROCESSING = 'PROCESSING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

export interface GeneratedImage {
  originalBase64: string; // The raw output from AI
  processedBase64: string; // The version displayed (potentially transparent)
}

/**
 * Processes the image to remove background and/or resize.
 */
export const processImage = async (
  base64Data: string,
  removeBg: boolean,
  targetSize: number
): Promise<string> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');

      if (!ctx) {
        reject(new Error('Could not get canvas context'));
        return;
      }

      // Set canvas to target size
      canvas.width = targetSize;
      canvas.height = targetSize;

      // Draw image (scaled)
      // If we are resizing down, we still draw the full source into the smaller canvas
      // The browser handles the interpolation (usually linear or bicubic)
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
      ctx.drawImage(img, 0, 0, targetSize, targetSize);

      if (removeBg) {
        const imageData = ctx.getImageData(0, 0, targetSize, targetSize);
        const data = imageData.data;

        // Simple algorithm: Assume Top-Left pixel is the background color
        const bgR = data[0];
        const bgG = data[1];
        const bgB = data[2];

        // Tolerance for "similarity" to background color
        const tolerance = 40; 

        for (let i = 0; i < data.length; i += 4) {
          const r = data[i];
          const g = data[i + 1];
          const b = data[i + 2];

          // Calculate distance from background color
          const distance = Math.sqrt(
            Math.pow(r - bgR, 2) +
            Math.pow(g - bgG, 2) +
            Math.pow(b - bgB, 2)
          );

          if (distance < tolerance) {
            data[i + 3] = 0; // Set Alpha to 0 (Transparent)
          }
        }
        ctx.putImageData(imageData, 0, 0);
      }

      resolve(canvas.toDataURL('image/png'));
    };
    img.onerror = (e) => reject(e);
    img.src = base64Data.startsWith('data:') ? base64Data : `data:image/png;base64,${base64Data}`;
  });
};

/**
 * Wraps a base64 PNG in an SVG tag to create a standalone SVG file.
 * This is a common technique for converting raster to "SVG" without tracing vectors.
 */
export const convertToSvgWrapper = (base64Png: string, size: number): string => {
  // Ensure we have a pure base64 string without the data URI prefix for usage inside href if needed, 
  // but <image> href accepts data URI directly.

  return `<?xml version="1.0" encoding="UTF-8" standalone="no"?>
<svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}" version="1.1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
    <title>Generated Logo</title>
    <g stroke="none" stroke-width="1" fill="none" fill-rule="evenodd">
        <image x="0" y="0" width="${size}" height="${size}" href="${base64Png}" />
    </g>
</svg>`;
};

export const downloadFile = (content: string, filename: string, type: 'png' | 'svg') => {
  const link = document.createElement('a');
  if (type === 'svg') {
    const blob = new Blob([content], { type: 'image/svg+xml;charset=utf-8' });
    link.href = URL.createObjectURL(blob);
  } else {
    link.href = content; // content is dataURL for PNG
  }
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import { GoogleGenAI } from "@google/genai";
import { LogoGenerationRequest } from "../types";

// Initialize the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateLogoFromGemini = async (request: LogoGenerationRequest): Promise<string> => {
  const { name, style, colorScheme } = request;

  // Constructed prompt optimized for logo generation
  // We explicitly ask for a solid background to make client-side removal easier.
  const prompt = `
    Design a professional, vector-style app icon or website logo for a brand named "${name}".
    Style: ${style}.
    Color Scheme: ${colorScheme}.

    Important Constraints:
    1. The design must be centered.
    2. Use a SOLID WHITE background (hex #FFFFFF).
    3. High contrast, clean lines, minimalist geometry.
    4. Do not include realistic photo textures.
    5. The output should look like a digital illustration or vector art.
    6. Make it suitable for a favicon (readable at small sizes).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: prompt }
        ]
      },
      config: {
        // Nano banana models don't support responseMimeType or detailed schemas, 
        // but we can request aspect ratio.
        imageConfig: {
            aspectRatio: "1:1",
        }
      }
    });

    // Parse response
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }

    throw new Error("No image data found in response");

  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {

  const baseStyles = "inline-flex items-center justify-center px-4 py-2 rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-dark disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-gradient-to-r from-indigo-500 to-purple-600 hover:from-indigo-600 hover:to-purple-700 text-white shadow-lg shadow-indigo-500/30 focus:ring-indigo-500",
    secondary: "bg-gray-700 hover:bg-gray-600 text-white focus:ring-gray-500",
    outline: "border border-gray-600 text-gray-300 hover:border-gray-400 hover:text-white bg-transparent focus:ring-gray-500",
    ghost: "text-gray-400 hover:text-white hover:bg-white/5"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
